import "../styles/hero.css";

function Hero() {

  return (

    <section className="hero">

      <div className="hero-content">

        <h3>Hello, I'm</h3>

        <h1>
          Harshini
        </h1>

        <h2>
          Frontend Developer
        </h2>

        <p>
          I build responsive and modern websites using React.js.
        </p>

        <button>
          View Projects
        </button>

      </div>

    </section>
  );
}

export default Hero;
